// src/pages/Register.jsx

import { useState } from "react";
import axios from "axios";

export default function Register() {

  const [emailError, setEmailError] = useState("");
  const [passwordError, setPasswordError] = useState("");

  const [form, setForm] = useState({
    role: "customer",
    skills: []
  });

  const jobs = [
    "Electrician",
    "Plumber",
    "Painter",
    "Carpenter",
    "Cleaner",
    "Technician",
    "Welder",
    "Driver"
  ];

  const handleSkills = (e) => {
    const values = Array.from(
      e.target.selectedOptions,
      option => option.value
    );

    setForm({
      ...form,
      skills: values
    });
  };

  const register = async () => {

    setEmailError("");
    setPasswordError("");

    // EMAIL CHECK
    if (!form.email?.includes("@gmail.com")) {
      setEmailError("Should contain @gmail.com");
      return;
    }

    // PASSWORD CHECK (6 DIGITS ONLY)
    const pass = form.password || "";

    if (!/^\d{6}$/.test(pass)) {
      setPasswordError("Password must be 6 digit number");
      return;
    }

    // PHONE CHECK
    if (!form.phone || form.phone.length !== 10) {
      alert("Phone number must be 10 digits");
      return;
    }

    try {

      const res = await axios.post(
        "http://localhost:5000/api/auth/register",
        form
      );

      localStorage.setItem(
        "user",
        JSON.stringify(res.data.user)
      );

      if (form.role === "customer") {
        window.location = "/customer-dashboard";
      } else {
        window.location = "/labour-dashboard";
      }

    } catch (err) {
      alert(err.response?.data?.message || "Registration Failed");
    }
  };

  return (

    <div style={styles.page}>

      <div style={styles.card}>

        <h1 style={styles.brand}>DailyMajdoor</h1>
        <h2 style={styles.title}>Register</h2>

        {/* EMAIL */}
        <input
          style={styles.input}
          placeholder="Email"
          value={form.email || ""}
          onChange={(e) => {
            setForm({ ...form, email: e.target.value });

            if (!e.target.value.includes("@gmail.com")) {
              setEmailError("Should contain @gmail.com");
            } else {
              setEmailError("");
            }
          }}
        />

        {emailError && <p style={styles.error}>{emailError}</p>}

        {/* PASSWORD */}
        <input
          type="password"
          style={styles.input}
          placeholder="6 digit password"
          value={form.password || ""}
          onChange={(e) => {
            const value = e.target.value.replace(/\D/g, "");
            setForm({ ...form, password: value });

            if (value.length !== 6) {
              setPasswordError("Password must be 6 digit number");
            } else {
              setPasswordError("");
            }
          }}
        />

        {passwordError && <p style={styles.error}>{passwordError}</p>}

        {/* PHONE */}
        <input
          type="tel"
          style={styles.input}
          placeholder="Phone Number"
          maxLength={10}
          value={form.phone || ""}
          onChange={(e) => {
            const value = e.target.value.replace(/\D/g, "");
            setForm({ ...form, phone: value });
          }}
        />

        {/* BUTTON */}
        <button style={styles.button} onClick={register}>
          Create Account
        </button>

      </div>

    </div>
  );
}

const styles = {

  page: {
    minHeight: "100vh",
    background: "#0f172a",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    fontFamily: "Arial"
  },

  card: {
    width: "340px",
    background: "#111827",
    border: "2px solid #f97316",
    borderRadius: "18px",
    padding: "22px"
  },

  brand: {
    textAlign: "center",
    color: "#fb923c",
    marginBottom: "10px"
  },

  title: {
    textAlign: "center",
    color: "white",
    marginBottom: "15px"
  },

  input: {
    width: "100%",
    padding: "12px",
    marginBottom: "10px",
    borderRadius: "10px",
    border: "1px solid #f97316",
    background: "#1f2937",
    color: "white"
  },

  error: {
    color: "red",
    fontSize: "11px",
    marginBottom: "10px"
  },

  button: {
    width: "100%",
    padding: "12px",
    border: "none",
    borderRadius: "10px",
    background: "#f97316",
    color: "white",
    fontWeight: "bold"
  }
};
